```javascript
function solve(n, edges) {
    class PriorityQueue {
        constructor() {
            this.heap = [];
        }
        add(time, node) {
            this.heap.push({ time, node });
            this.heapifyUp(this.heap.length - 1);
        }
        pop() {
            if (this.heap.length === 0) return null;
            const top = this.heap[0];
            this.heap[0] = this.heap.pop();
            this.heapifyDown(0);
            return top;
        }
        heapifyUp(index) {
            while (index > 0) {
                const parentIndex = Math.floor((index - 1) / 2);
                if (this.heap[parentIndex].time <= this.heap[index].time) {
                    break;
                }
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            }
        }
        heapifyDown(index) {
            const n = this.heap.length;
            while (index < n) {
                const left = 2 * index + 1;
                const right = 2 * index + 2;
                let smallest = index;
                if (left < n && this.heap[left].time < this.heap[smallest].time) {
                    smallest = left;
                }
                if (right < n && this.heap[right].time < this.heap[smallest].time) {
                    smallest = right;
                }
                if (smallest === index) break;
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                index = smallest;
            }
        }
        isEmpty() {
            return this.heap.length === 0;
        }
    }

    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, start, end] of edges) {
        adj[u].push([v, start, end]);
    }

    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;

    const pq = new PriorityQueue();
    pq.add(0, 0);

    while (!pq.isEmpty()) {
        const { time: t, node: u } = pq.pop();
        if (u === n - 1) return t;
        if (t > dist[u]) continue;

        for (const [v, start, end] of adj[u]) {
            if (t >= start && t <= end) {
                const new_time = t + 1;
                if (new_time < dist[v]) {
                    dist[v] = new_time;
                    pq.add(new_time, v);
                }
            }
        }

        const new_time_wait = t + 1;
        if (new_time_wait < dist[u]) {
            dist[u] = new_time_wait;
            pq.add(new_time_wait, u);
        }
    }

    return -1;
}
